/**
 * @fileoverview Button events — centralised event binding via AbortController.
 * @module module/Button/events
 */

import { emitEvent } from '../shared/emitEvent.js';

/**
 * Bind click and keyboard events on the button root.
 *
 * @param {Elements} root — the root element
 * @param {object} ctx — { disabled, loading, onClick }
 * @returns {AbortController}
 */
export function bindEvents(root, ctx) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };
    const el   = root[0];

    el.addEventListener('click', (e) => {
        if (ctx.disabled() || ctx.loading()) {
            e.preventDefault();
            e.stopPropagation();
            return;
        }
        emitEvent(el, 'click', { originalEvent: e });
        ctx.onClick?.(e);
    }, opts);

    el.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' || e.key === ' ') {
            if (ctx.disabled() || ctx.loading()) return;
            e.preventDefault();
            el.click();
        }
    }, opts);

    return ac;
}
