/**
 * @fileoverview Button component definition for JIT pipeline.
 * @module module/Button.def
 */

import { PART } from './Button/constants.js';

export const ButtonDef = {
    name: 'Button',
    tag: 'rui-button',

    tokens: {
        prefix: 'btn',
        tokens: {
            'font-size':    { ref: 'font.size-sm',       description: 'Button font size' },
            'font-stack':   { ref: 'font.family',        description: 'Font family' },
            'radius':       { ref: 'radius.md',          description: 'Border radius' },
            'px':           { value: '1rem',              description: 'Horizontal padding' },
            'h':            { value: '2.25rem',           description: 'Minimum button height' },
            'py':           { value: '0.5rem',            description: 'Vertical padding (md)' },
            'gap':          { ref: 'spacing.2',           description: 'Gap between icon and label' },
            'icon-size':    { value: '1rem',              description: 'Icon/spinner size' },

            // Default text/bg (overridden by variant)
            'bg':           { ref: 'color.accent',        description: 'Background' },
            'text':         { value: '#fff',              description: 'Text color' },
            'border':       { ref: 'color.accent',        description: 'Border color' },
            'bg-hover':     { value: 'color-mix(in srgb, var(--rui-accent), #000 10%)', description: 'Hover bg' },
            'text-hover':   { value: '#fff',              description: 'Hover text' },
            'border-hover': { value: 'color-mix(in srgb, var(--rui-accent), #000 10%)', description: 'Hover border' },
            'bg-active':    { value: 'color-mix(in srgb, var(--rui-accent), #000 20%)', description: 'Active bg' },
            'focus-ring':   { ref: 'color.accent',        description: 'Focus ring color' },

            // Size: sm
            'sm-font-size': { value: '0.75rem',           description: 'Small font size' },
            'sm-px':        { value: '0.75rem',           description: 'Small horizontal padding' },
            'sm-h':         { value: '1.75rem',           description: 'Small minimum height' },
            'sm-py':        { value: '0.375rem',          description: 'Small vertical padding' },
            'sm-gap':       { value: '0.25rem',           description: 'Small gap' },
            'sm-icon-size': { value: '0.875rem',          description: 'Small icon size' },

            // Size: lg
            'lg-font-size': { ref: 'font.size-base',     description: 'Large font size' },
            'lg-px':        { value: '1.5rem',            description: 'Large horizontal padding' },
            'lg-h':         { value: '2.75rem',           description: 'Large minimum height' },
            'lg-py':        { value: '0.625rem',          description: 'Large vertical padding' },
            'lg-gap':       { value: '0.5rem',            description: 'Large gap' },
            'lg-icon-size': { value: '1.25rem',           description: 'Large icon size' },

            // Variant: primary
            'primary-bg':           { ref: 'color.accent',    description: 'Primary bg' },
            'primary-text':         { value: '#fff',          description: 'Primary text' },
            'primary-border':       { ref: 'color.accent',    description: 'Primary border' },
            'primary-bg-hover':     { value: 'color-mix(in srgb, var(--rui-accent), #000 10%)', description: 'Primary hover bg' },
            'primary-border-hover': { value: 'color-mix(in srgb, var(--rui-accent), #000 10%)', description: 'Primary hover border' },
            'primary-bg-active':    { value: 'color-mix(in srgb, var(--rui-accent), #000 20%)', description: 'Primary active bg' },

            // Variant: success
            'success-bg':           { value: '#16a34a',       description: 'Success bg' },
            'success-text':         { value: '#fff',          description: 'Success text' },
            'success-border':       { value: '#16a34a',       description: 'Success border' },
            'success-bg-hover':     { value: '#15803d',       description: 'Success hover bg' },
            'success-border-hover': { value: '#15803d',       description: 'Success hover border' },
            'success-bg-active':    { value: '#166534',       description: 'Success active bg' },

            // Variant: warning
            'warning-bg':           { value: '#f59e0b',       description: 'Warning bg' },
            'warning-text':         { value: '#fff',          description: 'Warning text' },
            'warning-border':       { value: '#f59e0b',       description: 'Warning border' },
            'warning-bg-hover':     { value: '#d97706',       description: 'Warning hover bg' },
            'warning-border-hover': { value: '#d97706',       description: 'Warning hover border' },
            'warning-bg-active':    { value: '#b45309',       description: 'Warning active bg' },

            // Variant: danger
            'danger-bg':            { value: '#dc2626',       description: 'Danger bg' },
            'danger-text':          { value: '#fff',          description: 'Danger text' },
            'danger-border':        { value: '#dc2626',       description: 'Danger border' },
            'danger-bg-hover':      { value: '#b91c1c',       description: 'Danger hover bg' },
            'danger-border-hover':  { value: '#b91c1c',       description: 'Danger hover border' },
            'danger-bg-active':     { value: '#991b1b',       description: 'Danger active bg' },

            // Variant: neutral
            'neutral-bg':           { ref: 'color.bg-inset',  description: 'Neutral bg' },
            'neutral-text':         { ref: 'color.text',      description: 'Neutral text' },
            'neutral-border':       { ref: 'color.border',    description: 'Neutral border' },
            'neutral-bg-hover':     { ref: 'color.bg-hover',  description: 'Neutral hover bg' },
            'neutral-border-hover': { ref: 'color.border',    description: 'Neutral hover border' },
            'neutral-bg-active':    { ref: 'color.bg-inset',  description: 'Neutral active bg' },

            // Variant: ghost
            'ghost-text':           { ref: 'color.text',      description: 'Ghost text' },
            'ghost-bg-hover':       { ref: 'color.bg-hover',  description: 'Ghost hover bg' },
            'ghost-bg-active':      { ref: 'color.bg-inset',  description: 'Ghost active bg' },

            // Variant: outline
            'outline-text':         { ref: 'color.accent',    description: 'Outline text' },
            'outline-border':       { ref: 'color.accent',    description: 'Outline border' },
            'outline-bg-hover':     { ref: 'color.accent',    description: 'Outline hover bg' },
            'outline-text-hover':   { value: '#fff',          description: 'Outline hover text' },
            'outline-border-hover': { ref: 'color.accent',    description: 'Outline hover border' },
            'outline-bg-active':    { value: 'color-mix(in srgb, var(--rui-accent), #000 10%)', description: 'Outline active bg' },
        },
    },

    states: {
        initial: 'idle',
        states: {
            idle:     { on: { LOAD: 'loading', DISABLE: 'disabled' } },
            loading:  { on: { LOADED: 'idle', DISABLE: 'disabled' } },
            disabled: { on: { ENABLE: 'idle' } },
        },
    },

    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.ICON]: PART.ICON,
        [PART.LABEL]: PART.LABEL,
        [PART.SPINNER]: PART.SPINNER,
        [PART.SPINNER_RING]: PART.SPINNER_RING,
        [PART.SM_ROOT]: PART.SM_ROOT,
        [PART.LG_ROOT]: PART.LG_ROOT,
        [PART.PRIMARY]: PART.PRIMARY,
        [PART.SUCCESS]: PART.SUCCESS,
        [PART.WARNING]: PART.WARNING,
        [PART.DANGER]: PART.DANGER,
        [PART.NEUTRAL]: PART.NEUTRAL,
        [PART.GHOST]: PART.GHOST,
        [PART.OUTLINE]: PART.OUTLINE,
    },

    styles: {
        '@keyframes rui-spin': {
            'from': { transform: 'rotate(0deg)' },
            'to':   { transform: 'rotate(360deg)' },
        },
    },

    observedAttrs: ['disabled', 'loading', 'variant', 'size'],

    handlers: {
        root: {
            click(ctx, e) {
                if (ctx.disabled || ctx.loading) {
                    e.preventDefault();
                    e.stopPropagation();
                }
            },
        },
    },
};
