/**
 * @fileoverview Button constants — CSS classes, selectors, defaults, JIT parts.
 * @module module/Button/constants
 */

import { TRANSITION_INTERACTIVE } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:         'button',
    ICON:         'button-icon',
    LABEL:        'button-label',
    SPINNER:      'button-spinner',
    SPINNER_RING: 'button-spinner-ring',
    LOADING:      'is-loading',
    DISABLED:     'is-disabled',
});

/** DOM selectors */
export const SEL = Object.freeze({
    ROOT:  '.button',
    ICON:  '.button-icon',
    LABEL: '.button-label',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    variant: 'primary',    // primary | success | warning | danger | neutral | ghost | outline
    size: 'md',            // sm | md | lg
    disabled: false,
    loading: false,
    iconOnly: false,
    type: 'button',        // button | submit | reset
    text: '',
    icon: null,            // CSS class name shorthand for left icon (e.g. 'ri-settings-line')
    iconLeft: null,        // HTML string or CSS class for left icon
    iconRight: null,       // HTML string or CSS class for right icon
    onClick: null,
});

/** Semantic part names for JIT styling. */
export const PART = defineParts('Button', {
    ROOT        : { class: 'button-container', aliases: ['root', 'container'] },
    ICON        : { class: 'button-icon', aliases: ['icon'], tag: 'span' },
    LABEL       : { class: 'button-label', aliases: ['label'], tag: 'span' },
    SPINNER     : { class: 'button-spinner', aliases: ['spinner'], tag: 'span' },
    SPINNER_RING: { class: 'button-spinner-ring', aliases: ['spinner-ring'], tag: 'span' },
    SM_ROOT     : { class: 'button-container-sm', aliases: ['sm'] },
    LG_ROOT     : { class: 'button-container-lg', aliases: ['lg'] },
    PRIMARY     : { class: 'button-primary', aliases: ['primary'] },
    SUCCESS     : { class: 'button-success', aliases: ['success'] },
    WARNING     : { class: 'button-warning', aliases: ['warning'] },
    DANGER      : { class: 'button-danger', aliases: ['danger'] },
    NEUTRAL     : { class: 'button-neutral', aliases: ['neutral'] },
    GHOST       : { class: 'button-ghost', aliases: ['ghost'] },
    OUTLINE     : { class: 'button-outline', aliases: ['outline'] },
});

PART.ROOT.jit     = 'relative inline-flex items-stretch justify-center gap-[var(--btn-gap)] [font-family:var(--btn-font-stack)] text-[var(--btn-font-size)] font-semibold fg-[var(--btn-text)] bg-[var(--btn-bg)] [border:1px_solid_var(--btn-border)] rounded-[var(--btn-radius)] px-[var(--btn-px)] h-[var(--btn-h)] cursor-pointer select-none [white-space:nowrap] leading-none ' + TRANSITION_INTERACTIVE + ' hover:bg-[var(--btn-bg-hover)] hover:fg-[var(--btn-text-hover)] hover:[border-color:var(--btn-border-hover)] active:bg-[var(--btn-bg-active)] focus-visible:[outline:2px_solid_var(--btn-focus-ring)] focus-visible:[outline-offset:2px] {is-disabled}:opacity-50 {is-disabled}:cursor-not-allowed {is-disabled}:pointer-events-none {is-loading}:cursor-wait {is-loading}:pointer-events-none';
PART.ICON.jit     = 'inline-flex self-center items-center justify-center w-[var(--btn-icon-size)] h-[var(--btn-icon-size)] shrink-0 text-[var(--btn-icon-size)] [&>svg]:[width:100%] [&>svg]:[height:100%] {is-loading}:opacity-0';
PART.LABEL.jit    = 'flex items-center justify-center leading-none shrink-0 min-w-0 {is-loading}:opacity-0';
PART.SPINNER.jit  = 'absolute inset-0 z-10 flex items-center justify-center pointer-events-none';
PART.SPINNER_RING.jit = 'block w-[var(--btn-icon-size)] h-[var(--btn-icon-size)] shrink-0 rounded-full [border:2px_solid_color-mix(in_srgb,currentColor_35%,transparent)] [border-top-color:currentColor] [animation:rui-spin_0.6s_linear_infinite]';
PART.SM_ROOT.jit  = '[--btn-font-size:var(--btn-sm-font-size)] [--btn-px:var(--btn-sm-px)] [--btn-h:var(--btn-sm-h)] [--btn-gap:var(--btn-sm-gap)] [--btn-icon-size:var(--btn-sm-icon-size)]';
PART.LG_ROOT.jit  = '[--btn-font-size:var(--btn-lg-font-size)] [--btn-px:var(--btn-lg-px)] [--btn-h:var(--btn-lg-h)] [--btn-gap:var(--btn-lg-gap)] [--btn-icon-size:var(--btn-lg-icon-size)]';
PART.PRIMARY.jit  = '[--btn-bg:var(--btn-primary-bg)] [--btn-text:var(--btn-primary-text)] [--btn-border:var(--btn-primary-border)] [--btn-bg-hover:var(--btn-primary-bg-hover)] [--btn-text-hover:var(--btn-primary-text)] [--btn-border-hover:var(--btn-primary-border-hover)] [--btn-bg-active:var(--btn-primary-bg-active)] [--btn-focus-ring:var(--btn-primary-bg)]';
PART.SUCCESS.jit  = '[--btn-bg:var(--btn-success-bg)] [--btn-text:var(--btn-success-text)] [--btn-border:var(--btn-success-border)] [--btn-bg-hover:var(--btn-success-bg-hover)] [--btn-text-hover:var(--btn-success-text)] [--btn-border-hover:var(--btn-success-border-hover)] [--btn-bg-active:var(--btn-success-bg-active)] [--btn-focus-ring:var(--btn-success-bg)]';
PART.WARNING.jit  = '[--btn-bg:var(--btn-warning-bg)] [--btn-text:var(--btn-warning-text)] [--btn-border:var(--btn-warning-border)] [--btn-bg-hover:var(--btn-warning-bg-hover)] [--btn-text-hover:var(--btn-warning-text)] [--btn-border-hover:var(--btn-warning-border-hover)] [--btn-bg-active:var(--btn-warning-bg-active)] [--btn-focus-ring:var(--btn-warning-bg)]';
PART.DANGER.jit   = '[--btn-bg:var(--btn-danger-bg)] [--btn-text:var(--btn-danger-text)] [--btn-border:var(--btn-danger-border)] [--btn-bg-hover:var(--btn-danger-bg-hover)] [--btn-text-hover:var(--btn-danger-text)] [--btn-border-hover:var(--btn-danger-border-hover)] [--btn-bg-active:var(--btn-danger-bg-active)] [--btn-focus-ring:var(--btn-danger-bg)]';
PART.NEUTRAL.jit  = '[--btn-bg:var(--btn-neutral-bg)] [--btn-text:var(--btn-neutral-text)] [--btn-border:var(--btn-neutral-border)] [--btn-bg-hover:var(--btn-neutral-bg-hover)] [--btn-text-hover:var(--btn-neutral-text)] [--btn-border-hover:var(--btn-neutral-border-hover)] [--btn-bg-active:var(--btn-neutral-bg-active)] [--btn-focus-ring:var(--btn-neutral-bg)]';
PART.GHOST.jit    = '[--btn-bg:transparent] [--btn-text:var(--btn-ghost-text)] [--btn-border:transparent] [--btn-bg-hover:var(--btn-ghost-bg-hover)] [--btn-text-hover:var(--btn-ghost-text)] [--btn-border-hover:transparent] [--btn-bg-active:var(--btn-ghost-bg-active)] [--btn-focus-ring:var(--btn-ghost-text)]';
PART.OUTLINE.jit  = '[--btn-bg:transparent] [--btn-text:var(--btn-outline-text)] [--btn-border:var(--btn-outline-border)] [--btn-bg-hover:var(--btn-outline-bg-hover)] [--btn-text-hover:var(--btn-outline-text-hover)] [--btn-border-hover:var(--btn-outline-border-hover)] [--btn-bg-active:var(--btn-outline-bg-active)] [--btn-focus-ring:var(--btn-outline-border)]';