/**
 * @fileoverview Button barrel — re-exports from modular implementation.
 * @module module/Button
 */
import { default as razyui } from '../index.js';
import { ButtonDef as DEF } from './Button.def.js';
import Button from './Button/index.js';

razyui.Button = Button;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Button);
}

export default Button;

export const stylesheet = null;
