/**
 * @fileoverview Button view — DOM setup / teardown and state-machine effects.
 * @module module/Button/view
 */

import { CLS, PART } from './constants.js';

// ═══════════════════════════════════════
//  State Machine Effects (DOM updates)
// ═══════════════════════════════════════

export const SM_EFFECTS = {
    idle({ root, refs }) {
        root.removeClass(CLS.LOADING).removeClass(CLS.DISABLED);
        root[0].removeAttribute('aria-disabled');
        root[0].removeAttribute('aria-busy');
        if (refs.spinner) refs.spinner.style.display = 'none';
        if (refs.label) refs.label.classList.remove(CLS.LOADING);
        for (const icon of refs.icons) icon.classList.remove(CLS.LOADING);
    },
    loading({ root, refs }) {
        root.addClass(CLS.LOADING);
        root[0].setAttribute('aria-busy', 'true');
        if (refs.spinner) refs.spinner.style.display = '';
        if (refs.label) refs.label.classList.add(CLS.LOADING);
        for (const icon of refs.icons) icon.classList.add(CLS.LOADING);
    },
    disabled({ root }) {
        root.addClass(CLS.DISABLED);
        root[0].setAttribute('aria-disabled', 'true');
    },
    'loading:exit'({ root, refs }) {
        root.removeClass(CLS.LOADING);
        root[0].removeAttribute('aria-busy');
        if (refs.spinner) refs.spinner.style.display = 'none';
        if (refs.label) refs.label.classList.remove(CLS.LOADING);
        for (const icon of refs.icons) icon.classList.remove(CLS.LOADING);
    },
    'disabled:exit'({ root }) {
        root.removeClass(CLS.DISABLED);
        root[0].removeAttribute('aria-disabled');
    },
};

// ═══════════════════════════════════════
//  DOM Setup
// ═══════════════════════════════════════

/**
 * Build the button DOM structure inside the root element.
 *
 * @param {Elements} root — razyui-wrapped root element
 * @param {object} config
 * @returns {{ labelEl: Elements|null, spinnerEl: Elements|null }}
 */
export function setupDOM(root, config) {
    const { size, variant, text, iconOnly } = config;
    // Support `icon` shorthand as alias for `iconLeft`
    const iconLeft = config.iconLeft || config.icon || null;
    const iconRight = config.iconRight || null;

    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    // Size
    if (size === 'sm') {
        PART.SM_ROOT.apply(root);
    } else if (size === 'lg') {
        PART.LG_ROOT.apply(root);
    }

    // Variant
    const variantMap = {
        primary: PART.PRIMARY,
        success: PART.SUCCESS,
        warning: PART.WARNING,
        danger:  PART.DANGER,
        neutral: PART.NEUTRAL,
        ghost:   PART.GHOST,
        outline: PART.OUTLINE,
    };
    if (variantMap[variant]) {
        variantMap[variant].apply(root);
    }

    // Left icon
    if (iconLeft) {
        const $icon = PART.ICON.create();
        if (typeof iconLeft === 'string' && !iconLeft.includes('<')) {
            const i = document.createElement('i');
            i.className = iconLeft;
            $icon.append(i);
        } else {
            $icon[0].innerHTML = iconLeft;
        }
        root.append($icon);
    }

    // Label
    let labelEl = null;
    if (!iconOnly) {
        labelEl = PART.LABEL.create();
        labelEl.text(text);
        root.append(labelEl);
    }

    // Right icon
    if (iconRight) {
        const $icon = PART.ICON.create();
        if (typeof iconRight === 'string' && !iconRight.includes('<')) {
            const i = document.createElement('i');
            i.className = iconRight;
            $icon.append(i);
        } else {
            $icon[0].innerHTML = iconRight;
        }
        root.append($icon);
    }

    // Spinner: outer flex-centers; inner carries border + rotate (transform on inner only)
    const $spinner = PART.SPINNER.create({ 'aria-hidden': 'true' });
    $spinner.hide();
    const $ring = PART.SPINNER_RING.create();
    $spinner.append($ring);
    root.append($spinner);

    return { labelEl, spinnerEl: $spinner };
}

/**
 * Cleanup the button DOM.
 * @param {Elements} root
 */
export function cleanupDOM(root) {
    root.removeClass(CLS.ROOT);
    root[0].innerHTML = '';
}
